import React, { useEffect, useState } from 'react'
import "./Main.css"
import Country from "../Component/Country/Country"

function Main() {
    const [jsonData, setJsonData] = useState(null);
    useEffect(() => {
        // Function to fetch the JSON data
        const fetchJsonData = async () => {
          try {
            const response = await fetch('./data.json'); // Replace with the actual path to your JSON file
            if (!response.ok) {
              throw new Error('Failed to fetch data');
            }
            const data = await response.json();
            setJsonData(data);
          } catch (error) {
            console.error('Error fetching JSON data:', error);
          }
        };

        fetchJsonData();
      }, []);



  return (
    <div className="main-wrapper">
        <div className="main-container">
            <div className="row1-content">
                    <div className="row1-left">
                        <div className="input-search">
                            <span id="search-light" className="material-symbols-outlined">
                                search
                                </span>
                            <input type="text" placeholder="Search for a country..."/>
                        </div>
                    </div>
                    <div className="row1-right">
                        <div className="Filter-region">
                            <select name="" id="">
                                <option value="">Filter By Region</option>
                                <option value="">Africa</option>
                                <option value="">America</option>
                                <option value="">Asia</option>
                                <option value="">Europe</option>
                                <option value="">Ocenia</option>
                            </select>
                        </div>
                    </div>
            </div>
            <div className="row-contrys">
                <Country/>
            </div>
        </div>
    </div>
  )
}

export default Main
